/**
 * Export Routes
 *
 * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
 * Uses async job processing with status polling.
 *
 * Key endpoints:
 * - POST /export/pm-schedule - Queue PM schedule export
 * - POST /export/report - Queue report generation
 * - GET /export/:jobId - Get export job status and download URL
 * - GET /export/jobs - List export jobs for current user
 *
 * @see specs/005-api.md Section 5.15
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getExportService,
  type PmScheduleExportRequest,
  type ReportExportRequest,
  type ExportJobStatus,
  type ReportType,
} from '../../services/export';
import { SYSTEM_USER_ID } from '../../lib/constants';

// Singleton service instance
let exportService: ReturnType<typeof getExportService> | null = null;

function getService(): ReturnType<typeof getExportService> {
  if (!exportService) {
    exportService = getExportService();
  }
  return exportService;
}

export const exportRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * POST /export/pm-schedule
 *
 * Queue a PM schedule export job.
 *
 * Request Body:
 * - format: Export format ('xlsx' or 'csv')
 * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
 * - columns: Optional list of columns to include
 *
 * Returns 202 Accepted with job ID for polling.
 */
exportRoutes.post('/export/pm-schedule', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.format) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'format is required', requestId, {
          field: 'format',
          expected: ['xlsx', 'csv'],
        }),
        400
      );
    }

    if (!['xlsx', 'csv'].includes(body.format)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid format', requestId, {
          field: 'format',
          expected: ['xlsx', 'csv'],
          received: body.format,
        }),
        400
      );
    }

    // Get user from context (or use default for now)
    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;

    const request: PmScheduleExportRequest = {
      format: body.format,
      filters: body.filters,
      columns: body.columns,
      requestedBy: userId,
    };

    const result = await service.queuePmScheduleExport(request);

    return c.json(
      success(
        {
          jobId: result.jobId,
          status: result.status,
          estimatedSizeBytes: result.estimatedSizeBytes,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      ),
      202
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to queue export';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * POST /export/report
 *
 * Queue a report generation job.
 *
 * Request Body:
 * - reportType: Type of report to generate
 * - parameters: Report-specific parameters
 *
 * Report Types:
 * - WEEKLY_COMPLIANCE: Weekly PM compliance summary
 * - MONTHLY_SUMMARY: Monthly fleet maintenance summary
 * - FLEET_STATUS: Current fleet status report
 * - DRIFT_REPORT: Baseline drift analysis
 * - TCO_PROJECTION: Total cost of ownership projection
 * - BOW_WAVE_ANALYSIS: Maintenance clustering analysis
 * - MANHOUR_UTILIZATION: Man-hour utilization report
 *
 * Returns 202 Accepted with job ID for polling.
 */
exportRoutes.post('/export/report', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.reportType) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'reportType is required', requestId, {
          field: 'reportType',
        }),
        400
      );
    }

    const validTypes: ReportType[] = [
      'WEEKLY_COMPLIANCE',
      'MONTHLY_SUMMARY',
      'FLEET_STATUS',
      'DRIFT_REPORT',
      'TCO_PROJECTION',
      'BOW_WAVE_ANALYSIS',
      'MANHOUR_UTILIZATION',
    ];

    if (!validTypes.includes(body.reportType)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid reportType', requestId, {
          field: 'reportType',
          expected: validTypes,
          received: body.reportType,
        }),
        400
      );
    }

    // Get user from context (or use default for now)
    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;

    const request: ReportExportRequest = {
      reportType: body.reportType,
      parameters: body.parameters ?? {},
      requestedBy: userId,
    };

    const result = await service.queueReportExport(request);

    return c.json(
      success(
        {
          jobId: result.jobId,
          status: result.status,
          estimatedSizeBytes: result.estimatedSizeBytes,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      ),
      202
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to queue report';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /export/jobs
 *
 * List export jobs for the current user.
 * NOTE: This route MUST be defined before /export/:jobId to avoid route collision.
 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 20, max: 100)
 * - status: Filter by status (comma-separated: QUEUED,PROCESSING,COMPLETED,FAILED,EXPIRED)
 * - type: Filter by type (pm_schedule or report)
 */
exportRoutes.get('/export/jobs', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    // Get user from context (or use default for now)
    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;

    // Parse query parameters
    const pagination = parsePaginationQuery({
      page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
      pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    });

    // Parse status filter
    let statusFilter: ExportJobStatus[] | undefined;
    const statusParam = c.req.query('status');
    if (statusParam) {
      statusFilter = statusParam.split(',') as ExportJobStatus[];
    }

    // Parse type filter
    const typeParam = c.req.query('type');
    const typeFilter = typeParam === 'pm_schedule' || typeParam === 'report' ? typeParam : undefined;

    const result = service.listExportJobs(userId, {
      page: pagination.page,
      pageSize: pagination.pageSize,
      status: statusFilter,
      type: typeFilter,
    });

    // Transform jobs to API response format
    const jobs = result.jobs.map((job) => ({
      jobId: job.id,
      type: job.type,
      status: job.status,
      format: job.format,
      createdAt: job.createdAt.toISOString(),
      ...(job.completedAt && { completedAt: job.completedAt.toISOString() }),
      ...(job.downloadUrl && { downloadUrl: job.downloadUrl }),
      ...(job.expiresAt && { expiresAt: job.expiresAt.toISOString() }),
      ...(job.fileSizeBytes && { fileSizeBytes: job.fileSizeBytes }),
      ...(job.reportType && { reportType: job.reportType }),
    }));

    return c.json(
      paginatedSuccess(jobs, {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: result.total,
      }),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to list export jobs';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /export/:jobId
 *
 * Get export job status and download URL.
 *
 * Path Parameters:
 * - jobId: Export job ID
 *
 * Response includes:
 * - jobId: Job identifier
 * - status: Current status (QUEUED, PROCESSING, COMPLETED, FAILED, EXPIRED)
 * - downloadUrl: URL to download file (only when COMPLETED)
 * - expiresAt: When the download URL expires
 * - fileSizeBytes: Actual file size (only when COMPLETED)
 * - errorMessage: Error details (only when FAILED)
 */
exportRoutes.get('/export/:jobId', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const jobId = c.req.param('jobId');

    if (!jobId) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'jobId is required', requestId),
        400
      );
    }

    const result = await service.getExportJobStatus(jobId);

    return c.json(
      success(
        {
          jobId: result.jobId,
          status: result.status,
          ...(result.downloadUrl && { downloadUrl: result.downloadUrl }),
          ...(result.expiresAt && { expiresAt: result.expiresAt }),
          ...(result.fileSizeBytes && { fileSizeBytes: result.fileSizeBytes }),
          ...(result.errorMessage && { errorMessage: result.errorMessage }),
          ...(result.progress !== undefined && { progress: result.progress }),
        },
        { timing: { durationMs: getRequestDuration(c) } }
      ),
      200
    );
  } catch (err) {
    if (err instanceof Error && err.message.includes('not found')) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, {
          jobId: c.req.param('jobId'),
        }),
        404
      );
    }

    const message = err instanceof Error ? err.message : 'Failed to get job status';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * POST /export/cleanup
 *
 * Trigger cleanup of expired export jobs.
 * Admin-only endpoint.
 */
exportRoutes.post('/export/cleanup', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const cleanedCount = service.cleanupExpiredExports();

    return c.json(
      success(
        {
          message: 'Cleanup completed',
          cleanedCount,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to cleanup exports';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

