   819→
   820→    // Write to file using synchronous fs createWriteStream
   821→    await new Promise<void>((resolve, reject) => {
   822→      const writeStream = fsSync.createWriteStream(filePath);
   823→      pdfDoc.pipe(writeStream);
   824→      pdfDoc.end();
   825→      writeStream.on('finish', resolve);
   826→      writeStream.on('error', reject);
   827→    });
   828→
   829→    const stats = await fs.stat(filePath);
   830→    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);
   831→
   832→    // Estimate page count (roughly 40 rows per page in landscape)
   833→    const estimatedPageCount = Math.max(1, Math.ceil(reportData.rowCount / 40));
   834→
   835→    return {
   836→      jobId,
   837→      type,
   838→      format: 'pdf',
   839→      filePath,
   840→      fileName,
   841→      fileSizeBytes: stats.size,
   842→      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
   843→      expiresAt,
   844→      generatedAt: new Date(),
   845→      rowCount: reportData.rowCount,
   846→      pageCount: estimatedPageCount,
   847→    };
   848→  });
   849→}
