/**
 * MMS Report Worker Processor
 *
 * BullMQ job processor for PDF and Excel report generation.
 * Handles export of PM schedules, fleet status, and various analytical reports.
 *
 * Supported Report Types:
 * - pm_schedule: PM Schedule export (Excel/CSV)
 * - fleet_status: Fleet status overview (PDF)
 * - drift_report: Drift analysis report (PDF)
 * - tco_projection: Total Cost of Ownership projection (PDF)
 *
 * Report Generation:
 * - Excel: Uses ExcelJS for .xlsx generation with formatting
 * - PDF: Uses pdfmake for PDF generation with structured layouts
 *
 * Job Flow:
 * 1. Receive ReportJobData from queue
 * 2. Fetch data based on report type and filters
 * 3. Generate report in requested format
 * 4. Save to file storage
 * 5. Update job status with download URL
 *
 * @see specs/005-api.md Section 5.15
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type ReportJobData } from '../../lib/queue';
import { ValidationError } from '../../lib/errors';
import * as fs from 'fs/promises';
import * as fsSync from 'fs';
import * as path from 'path';
import ExcelJS from 'exceljs';
import PdfPrinter from 'pdfmake';
import type { TDocumentDefinitions, Content, TableCell } from 'pdfmake/interfaces';

// Domain services for data fetching
import { getFleetService, type FleetStatistics } from '../../services/fleet';
import {
  getDriftMonitorService,
  type TrainDriftAnalysis,
  type DriftAlert,
  type DriftAnalysisResult,
  type DriftAnalysisSuccess,
} from '../../services/drift-monitor';
import { getCostingService, type TCOProjection, type YearlyCost } from '../../services/costing';
import { db } from '../../lib/db/connection';
import {
  pmSchedule,
  trains,
  pmTypes,
  depots,
  tracks,
  fleets,
} from '../../lib/db/schema';
import { eq, and, gte, lte, isNull, inArray, asc } from 'drizzle-orm';
import { format } from 'date-fns';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'report' });

/** Output directory for generated reports */
const REPORTS_OUTPUT_DIR = process.env['REPORTS_OUTPUT_DIR'] ?? '/tmp/mms-reports';

/**
 * Base URL for report downloads
 * Note: In production or when using dynamic ports, set REPORTS_BASE_URL environment variable
 * to match the actual server address (e.g., http://localhost:<actual-port>/exports)
 */
const REPORTS_BASE_URL = process.env['REPORTS_BASE_URL'] ?? 'http://localhost:3000/exports';

/** Report retention period in hours */
const REPORT_RETENTION_HOURS = parseInt(process.env['REPORT_RETENTION_HOURS'] ?? '24', 10);

// =============================================================================
// Types
// =============================================================================

/** Report generation result */
export interface ReportResult {
  jobId: string;
  type: string;
  format: 'pdf' | 'excel';
  filePath: string;
  fileName: string;
  fileSizeBytes: number;
  downloadUrl: string;
  expiresAt: Date;
  generatedAt: Date;
  rowCount?: number;
  pageCount?: number;
}

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process report generation job
 *
 * Generates PDF or Excel reports based on the job configuration.
 * Saves output to file storage and returns download URL.
 */
export async function processReportJob(
  context: WorkerJobContext<ReportJobData>
): Promise<ReportResult> {
  return withSpan('worker.report.process', async (span) => {
    const { id, data } = context;
    const { type, format, filters, requestedBy } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('reportType', type);
    span.setAttribute('format', format);
    span.setAttribute('requestedBy', requestedBy);

    log.info(
      {
        jobId: id,
        type,
        format,
        requestedBy,
        filters: Object.keys(filters ?? {}),
      },
      'Processing report generation job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
    await context.log(`Initializing ${type} report generation (${format})`);

    // Ensure output directory exists
    await ensureOutputDir();

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 20 });
    await context.log('Fetching report data');

    // Fetch data based on report type
    const reportData = await fetchReportData(type, filters);
    span.setAttribute('report.dataRows', reportData.rowCount);

    await context.log(`Loaded ${reportData.rowCount} records for report`);

    // Update progress: generating report
    await context.updateProgress({ stage: 'GENERATING', percent: 50 });
    await context.log(`Generating ${format.toUpperCase()} report`);

    // Generate report based on format
    let result: ReportResult;

    if (format === 'excel') {
      result = await generateExcelReport(id, type, reportData);
    } else {
      result = await generatePdfReport(id, type, reportData);
    }

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    log.info(
      {
        jobId: id,
        filePath: result.filePath,
        fileSizeBytes: result.fileSizeBytes,
        downloadUrl: result.downloadUrl,
        expiresAt: result.expiresAt,
      },
      'Report generation complete'
    );

    await context.log(
      `Report generated: ${result.fileName} (${formatFileSize(result.fileSizeBytes)})`
    );
    await context.log(`Download URL: ${result.downloadUrl}`);
    await context.log(`Expires: ${result.expiresAt.toISOString()}`);

    // Record metrics
    span.setAttribute('report.fileSizeBytes', result.fileSizeBytes);
    span.setAttribute('report.fileName', result.fileName);

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

// =============================================================================
// Data Fetching
// =============================================================================

interface ReportData {
  rowCount: number;
  data: Record<string, unknown>[];
  metadata: Record<string, unknown>;
}

/** PM Schedule row for report */
interface PmScheduleRow {
  trainNumber: string;
  fleetCode: string;
  pmCode: string;
  targetDate: string;
  status: string;
  constraintStart: string | null;
  constraintEnd: string | null;
  assignedDepot: string | null;
  assignedTrack: string | null;
  estimatedHours: number | null;
  maximoWoId: string | null;
  isLocked: boolean;
}

/** Fleet status row for report */
interface FleetStatusRow {
  fleetCode: string;
  fleetName: string;
  totalTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  avgMileageKm: number;
  minMileageKm: number;
  maxMileageKm: number;
  stdDevMileageKm: number;
}

/** Drift report row for report */
interface DriftReportRow {
  trainNumber: string;
  fleetCode: string;
  baselineProjectedKm: number;
  actualKm: number;
  mileageDriftPct: number;
  avgPmDriftDays: number;
  maxPmDriftDays: number;
  requiresReplan: boolean;
  replanReason: string | null;
}

/** TCO projection row for report */
interface TcoProjectionRow {
  fiscalYear: number;
  laborCost: number;
  materialCost: number;
  overheadCost: number;
  totalCost: number;
  pmCount: number;
  inflationFactor: number;
}

/**
 * Fetch data for report generation
 */
async function fetchReportData(
  type: string,
  filters?: Record<string, unknown>
): Promise<ReportData> {
  return withSpan('report.fetchData', async (span) => {
    span.setAttribute('reportType', type);

    switch (type) {
      case 'pm_schedule':
        return fetchPmScheduleData(filters);

      case 'fleet_status':
        return fetchFleetStatusData(filters);

      case 'drift_report':
        return fetchDriftReportData(filters);

      case 'tco_projection':
        return fetchTcoProjectionData(filters);

      default:
        throw new ValidationError(`Unsupported report type: ${type}`, {
          field: 'type',
          context: { supported: ['pm_schedule', 'fleet_status', 'drift_report', 'tco_projection'] },
        });
    }
  });
}

/**
 * Fetch PM schedule data from database
 */
async function fetchPmScheduleData(filters?: Record<string, unknown>): Promise<ReportData> {
  // Parse filters
  const startDate = filters?.['startDate'] as string | undefined;
  const endDate = filters?.['endDate'] as string | undefined;
  const fleetId = filters?.['fleetId'] as string | undefined;
  const depotId = filters?.['depotId'] as string | undefined;
  const statusFilter = filters?.['status'] as string[] | undefined;

  // Build query conditions
  const conditions = [isNull(pmSchedule.scenarioId)];

  if (startDate) {
    conditions.push(gte(pmSchedule.targetDate, startDate));
  }
  if (endDate) {
    conditions.push(lte(pmSchedule.targetDate, endDate));
  }
  if (statusFilter?.length) {
    conditions.push(inArray(pmSchedule.status, statusFilter as ('SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'DEFERRED' | 'CANCELLED')[]));
  }
  if (fleetId) {
    conditions.push(eq(fleets.id, fleetId));
  }
  if (depotId) {
    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
  }

  // Query with joins
  const results = await db
    .select({
      trainNumber: trains.trainNumber,
      fleetCode: fleets.code,
      pmCode: pmTypes.pmCode,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      assignedDepot: depots.name,
      assignedTrack: tracks.trackNumber,
      estimatedHours: pmTypes.estimatedHours,
      maximoWoId: pmSchedule.maximoWoId,
      isLocked: pmSchedule.isLocked,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .where(and(...conditions))
    .orderBy(asc(pmSchedule.targetDate), asc(trains.trainNumber));

  const rows: PmScheduleRow[] = results.map((r) => ({
    trainNumber: r.trainNumber,
    fleetCode: r.fleetCode,
    pmCode: r.pmCode,
    targetDate: r.targetDate,
    status: r.status ?? 'SCHEDULED', // Default to SCHEDULED if null
    constraintStart: r.constraintStart,
    constraintEnd: r.constraintEnd,
    assignedDepot: r.assignedDepot,
    assignedTrack: r.assignedTrack,
    estimatedHours: r.estimatedHours ? Number(r.estimatedHours) : null,
    maximoWoId: r.maximoWoId,
    isLocked: r.isLocked ?? false, // Default to false if null
  }));

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'pm_schedule',
      columns: [
        'trainNumber', 'fleetCode', 'pmCode', 'targetDate', 'status',
        'constraintStart', 'constraintEnd', 'assignedDepot', 'assignedTrack',
        'estimatedHours', 'maximoWoId', 'isLocked',
      ],
      generatedAt: new Date().toISOString(),
      filters: { startDate, endDate, fleetId, depotId, status: statusFilter },
    },
  };
}

/**
 * Fetch fleet status data using FleetService
 */
async function fetchFleetStatusData(filters?: Record<string, unknown>): Promise<ReportData> {
  const fleetService = getFleetService();

  // Get all fleet statistics
  const allStats = await fleetService.getAllFleetStatistics();

  // Optionally filter by fleetId
  const fleetId = filters?.['fleetId'] as string | undefined;
  const filteredStats = fleetId
    ? allStats.filter((s) => s.fleetId === fleetId || s.fleetCode === fleetId)
    : allStats;

  const rows: FleetStatusRow[] = filteredStats.map((s: FleetStatistics) => ({
    fleetCode: s.fleetCode,
    fleetName: s.fleetCode, // FleetStatistics has fleetCode but not fleetName
    totalTrains: s.totalTrains,
    fitTrains: s.fitTrains,
    restrictedTrains: s.restrictedTrains,
    groundedTrains: s.groundedTrains,
    avgMileageKm: Math.round(s.averageMileageKm),
    minMileageKm: s.minMileageKm,
    maxMileageKm: s.maxMileageKm,
    stdDevMileageKm: Math.round(s.mileageStdDevKm),
  }));

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'fleet_status',
      columns: [
        'fleetCode', 'fleetName', 'totalTrains', 'fitTrains', 'restrictedTrains',
        'groundedTrains', 'avgMileageKm', 'minMileageKm', 'maxMileageKm', 'stdDevMileageKm',
      ],
      generatedAt: new Date().toISOString(),
      filters: { fleetId },
    },
  };
}

/**
 * Fetch drift report data using DriftMonitorService
 */
async function fetchDriftReportData(filters?: Record<string, unknown>): Promise<ReportData> {
  const driftService = getDriftMonitorService();

  // Run or get latest drift analysis
  const analysisDate = filters?.['analysisDate'] as string | undefined;
  const analysisDateObj = analysisDate ? new Date(analysisDate) : undefined;
  const result: DriftAnalysisResult = await driftService.runDriftAnalysis(analysisDateObj);

  // Check if analysis was skipped (discriminated union check)
  if (result.skipped) {
    return {
      rowCount: 0,
      data: [],
      metadata: {
        reportType: 'drift_report',
        status: 'SKIPPED',
        reason: result.reason,
        generatedAt: new Date().toISOString(),
        filters,
      },
    };
  }

  // Type narrowing - result is now DriftAnalysisSuccess
  const successResult = result as DriftAnalysisSuccess;

  // Extract train analyses
  const trainAnalyses = successResult.trainAnalyses;

  const rows: DriftReportRow[] = trainAnalyses.map((t: TrainDriftAnalysis) => ({
    trainNumber: t.trainNumber,
    fleetCode: '', // TrainDriftAnalysis doesn't have fleetCode; would need separate lookup
    baselineProjectedKm: t.baselineProjectedKm,
    actualKm: t.actualKm,
    mileageDriftPct: t.mileageDriftPct,
    avgPmDriftDays: t.avgPmDriftDays,
    maxPmDriftDays: t.maxPmDriftDays,
    requiresReplan: t.requiresReplan,
    replanReason: t.replanReason ?? null,
  }));

  // Get summary and alerts
  const summary = successResult.summary;
  const alerts = successResult.alerts;

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'drift_report',
      baselineId: successResult.baselineId,
      analysisDate: successResult.analysisDate,
      summary: {
        totalTrainsAnalyzed: summary.totalTrains,
        trainsRequiringReplan: summary.trainsRequiringReplan,
        avgMileageDriftPct: summary.avgFleetDriftPct,
        maxPmDriftDays: 0, // Not directly available in summary, would need to calculate
      },
      alerts: alerts.map((a: DriftAlert) => ({
        severity: a.severity,
        type: a.type,
        message: a.message,
        trainNumber: a.trainNumber,
      })),
      columns: [
        'trainNumber', 'fleetCode', 'baselineProjectedKm', 'actualKm', 'mileageDriftPct',
        'avgPmDriftDays', 'maxPmDriftDays', 'requiresReplan', 'replanReason',
      ],
      generatedAt: new Date().toISOString(),
      filters,
    },
  };
}

/**
 * Fetch TCO projection data using CostingService
 */
async function fetchTcoProjectionData(filters?: Record<string, unknown>): Promise<ReportData> {
  const costingService = getCostingService();

  // Parse filters - ProjectTCORequest only has horizonYears, scenarioId, depotId
  const horizonYears = (filters?.['horizonYears'] as number) ?? 12;
  const depotId = filters?.['depotId'] as string | undefined;
  const scenarioId = filters?.['scenarioId'] as string | undefined;

  // Project TCO
  const projection: TCOProjection = await costingService.projectTCO({
    horizonYears,
    depotId,
    scenarioId,
  });

  // Calculate overhead as 18% of (labor + material) for each year
  const OVERHEAD_RATE = 0.18;
  const rows: TcoProjectionRow[] = projection.projections.map((p: YearlyCost) => {
    const overheadCost = (p.laborCost + p.materialCost) * OVERHEAD_RATE;
    return {
      fiscalYear: p.fiscalYear,
      laborCost: p.laborCost,
      materialCost: p.materialCost,
      overheadCost: Math.round(overheadCost),
      totalCost: p.totalCost,
      pmCount: p.pmCount,
      inflationFactor: p.inflationFactor,
    };
  });

  // Calculate total overhead cost from the rows
  const totalOverheadCost = rows.reduce((sum, r) => sum + r.overheadCost, 0);

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'tco_projection',
      horizonYears,
      summary: {
        totalLaborCost: projection.summary.totalLaborCost,
        totalMaterialCost: projection.summary.totalMaterialCost,
        totalOverheadCost: totalOverheadCost,
        grandTotal: projection.summary.totalCost,
        npv: projection.summary.npv,
        avgAnnualCost: projection.summary.avgAnnualCost,
      },
      columns: [
        'fiscalYear', 'laborCost', 'materialCost', 'overheadCost', 'totalCost',
        'pmCount', 'inflationFactor',
      ],
      generatedAt: new Date().toISOString(),
      filters: { horizonYears, depotId, scenarioId },
    },
  };
}

