// Define fonts for pdfmake (using Roboto which comes bundled)
const fonts = {
  Roboto: {
    normal: 'node_modules/pdfmake/build/vfs_fonts.js',
    bold: 'node_modules/pdfmake/build/vfs_fonts.js',
    italics: 'node_modules/pdfmake/build/vfs_fonts.js',
    bolditalics: 'node_modules/pdfmake/build/vfs_fonts.js',
  },
};

/**
 * Generate PDF report using pdfmake
 */
async function generatePdfReport(
  jobId: string,
  type: string,
  reportData: ReportData
): Promise<ReportResult> {
  return withSpan('report.generatePdf', async (span) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const fileName = `${type}_${timestamp}.pdf`;
    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);

    span.setAttribute('report.fileName', fileName);
    span.setAttribute('report.filePath', filePath);

    // Create PDF document definition
    const docDefinition = createPdfDocDefinition(type, reportData);

    // Create PDF printer
    const printer = new PdfPrinter(fonts);
    const pdfDoc = printer.createPdfKitDocument(docDefinition);

    // Write to file using synchronous fs createWriteStream
    await new Promise<void>((resolve, reject) => {
      const writeStream = fsSync.createWriteStream(filePath);
      pdfDoc.pipe(writeStream);
      pdfDoc.end();
      writeStream.on('finish', resolve);
      writeStream.on('error', reject);
    });

    const stats = await fs.stat(filePath);
    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);

    // Estimate page count (roughly 40 rows per page in landscape)
    const estimatedPageCount = Math.max(1, Math.ceil(reportData.rowCount / 40));

    return {
      jobId,
      type,
      format: 'pdf',
      filePath,
      fileName,
      fileSizeBytes: stats.size,
      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
      expiresAt,
      generatedAt: new Date(),
      rowCount: reportData.rowCount,
      pageCount: estimatedPageCount,
    };
  });
}

/**
 * Create PDF document definition for pdfmake
 */
function createPdfDocDefinition(type: string, reportData: ReportData): TDocumentDefinitions {
  const columns = (reportData.metadata['columns'] as string[]) ?? [];
  const generatedAt = reportData.metadata['generatedAt'] as string;

  // Build content array
  const content: Content[] = [];

  // Header
  content.push({
    text: `MMS ${formatReportTitle(type)}`,
    style: 'header',
    margin: [0, 0, 0, 10],
  });

  // Report info
  content.push({
    text: [
      { text: 'Generated: ', bold: true },
      format(new Date(generatedAt), 'PPpp'),
      '  |  ',
      { text: 'Records: ', bold: true },
      String(reportData.rowCount),
    ],
    style: 'subheader',
    margin: [0, 0, 0, 15],
  });

  // Add summary section for specific report types
  if (type === 'tco_projection' && reportData.metadata['summary']) {
    content.push(createTcoSummaryContent(reportData.metadata['summary'] as Record<string, number>));
  }

  if (type === 'drift_report' && reportData.metadata['summary']) {
    content.push(createDriftSummaryContent(
      reportData.metadata['summary'] as Record<string, number>,
      reportData.metadata['alerts'] as Array<{ severity: string; message: string }> | undefined
    ));
  }

  if (type === 'fleet_status') {
    content.push(createFleetSummaryContent(reportData.data as unknown as FleetStatusRow[]));
  }

  // Data table
  if (reportData.rowCount > 0 && columns.length > 0) {
    content.push({
      text: 'Detailed Data',
      style: 'sectionHeader',
      margin: [0, 20, 0, 10],
    });

    content.push(createDataTable(columns, reportData.data));
  } else {
    content.push({
      text: 'No data available for the specified filters.',
      style: 'noData',
      margin: [0, 20, 0, 0],
    });
  }

  // Footer with page numbers
  return {
    pageSize: 'A4',
    pageOrientation: 'landscape',
    pageMargins: [40, 60, 40, 60],
    header: (currentPage: number, pageCount: number) => ({
      columns: [
        { text: 'MMS Report', style: 'pageHeader' },
        { text: `Page ${currentPage} of ${pageCount}`, style: 'pageHeader', alignment: 'right' },
      ],
      margin: [40, 20, 40, 10],
    }),
    footer: () => ({
      text: 'Metro Fleet Mileage Management System - Confidential',
      style: 'footer',
      alignment: 'center',
      margin: [40, 10, 40, 20],
    }),
    content,
    styles: {
      header: {
        fontSize: 18,
        bold: true,
        color: '#2E5A88',
      },
      subheader: {
        fontSize: 10,
        color: '#666666',
      },
      sectionHeader: {
        fontSize: 14,
        bold: true,
        color: '#2E5A88',
      },
      tableHeader: {
        bold: true,
        fontSize: 8,
        color: 'white',
        fillColor: '#2E5A88',
      },
      tableCell: {
        fontSize: 7,
      },
      tableCellAlt: {
        fontSize: 7,
        fillColor: '#F5F5F5',
      },
      summaryLabel: {
        fontSize: 10,
        bold: true,
      },
      summaryValue: {
        fontSize: 10,
      },
      alertCritical: {
        fontSize: 9,
        color: '#D32F2F',
      },
      alertHigh: {
        fontSize: 9,
        color: '#F57C00',
      },
      alertMedium: {
        fontSize: 9,
        color: '#FBC02D',
      },
      noData: {
        fontSize: 12,
        italics: true,
        color: '#999999',
      },
      pageHeader: {
        fontSize: 8,
        color: '#999999',
      },
      footer: {
        fontSize: 8,
        color: '#999999',
      },
    },
    defaultStyle: {
      font: 'Roboto',
    },
  };
}

/**
 * Create data table for PDF
 */
function createDataTable(columns: string[], data: Record<string, unknown>[]): Content {
  // Limit columns displayed based on page width
  const displayColumns = columns.slice(0, 10);

  // Header row
  const headerRow: TableCell[] = displayColumns.map((col) => ({
    text: formatColumnHeader(col),
    style: 'tableHeader',
    alignment: 'center',
  }));

  // Data rows
  const dataRows: TableCell[][] = data.map((row, index) =>
    displayColumns.map((col) => ({
      text: String(formatCellValue(row[col], col) ?? ''),
      style: index % 2 === 0 ? 'tableCell' : 'tableCellAlt',
      alignment: isNumericColumn(col) ? 'right' : 'left',
    }))
  );

  // Calculate column widths (equal distribution)
  const colWidth = (842 - 80) / displayColumns.length; // A4 landscape width minus margins
  const widths = displayColumns.map(() => colWidth);

  return {
    table: {
      headerRows: 1,
      widths,
      body: [headerRow, ...dataRows],
    },
    layout: {
      hLineWidth: () => 0.5,
      vLineWidth: () => 0.5,
      hLineColor: () => '#DDDDDD',
      vLineColor: () => '#DDDDDD',
      paddingLeft: () => 4,
      paddingRight: () => 4,
      paddingTop: () => 2,
      paddingBottom: () => 2,
    },
  };
}

/**
 * Check if column contains numeric data
 */
function isNumericColumn(col: string): boolean {
  const numericCols = [
    'totalTrains', 'fitTrains', 'restrictedTrains', 'groundedTrains',
    'avgMileageKm', 'minMileageKm', 'maxMileageKm', 'stdDevMileageKm',
    'baselineProjectedKm', 'actualKm', 'mileageDriftPct', 'avgPmDriftDays',
    'maxPmDriftDays', 'fiscalYear', 'laborCost', 'materialCost',
    'overheadCost', 'totalCost', 'pmCount', 'inflationFactor', 'estimatedHours',
  ];
  return numericCols.includes(col);
}

/**
 * Create TCO summary content for PDF
 */
function createTcoSummaryContent(summary: Record<string, number>): Content {
  return {
    columns: [
      {
        width: '50%',
        stack: [
          { text: 'TCO Summary', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Total Labor Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalLaborCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Material Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalMaterialCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Overhead Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalOverheadCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Grand Total:', style: 'summaryLabel', bold: true }, { text: formatCurrency(summary['grandTotal']), style: 'summaryValue', alignment: 'right', bold: true }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
      {
        width: '50%',
        stack: [
          { text: 'Financial Metrics', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Net Present Value (NPV):', style: 'summaryLabel' }, { text: formatCurrency(summary['npv']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Average Annual Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['avgAnnualCost']), style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
    ],
    margin: [0, 0, 0, 20],
  };
}

/**
 * Create drift summary content for PDF
 */
function createDriftSummaryContent(
  summary: Record<string, number>,
  alerts?: Array<{ severity: string; message: string }>
): Content {
  const content: Content[] = [
    {
      columns: [
        {
          width: '50%',
          stack: [
            { text: 'Drift Analysis Summary', style: 'sectionHeader', margin: [0, 0, 0, 10] },
            {
              table: {
                widths: ['*', 'auto'],
                body: [
                  [{ text: 'Total Trains Analyzed:', style: 'summaryLabel' }, { text: String(summary['totalTrainsAnalyzed']), style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Trains Requiring Replan:', style: 'summaryLabel' }, { text: String(summary['trainsRequiringReplan']), style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Average Mileage Drift:', style: 'summaryLabel' }, { text: `${summary['avgMileageDriftPct']?.toFixed(2)}%`, style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Maximum PM Drift:', style: 'summaryLabel' }, { text: `${summary['maxPmDriftDays']} days`, style: 'summaryValue', alignment: 'right' }],
                ],
              },
              layout: 'noBorders',
            },
          ],
        },
      ],
      margin: [0, 0, 0, 10],
    },
  ];

  // Add alerts if present
  if (alerts && alerts.length > 0) {
    content.push({
      text: 'Active Alerts',
      style: 'sectionHeader',
      margin: [0, 10, 0, 5],
    });

    const alertList = alerts.slice(0, 5).map((alert) => ({
      text: `• ${alert.message}`,
      style: alert.severity === 'CRITICAL' ? 'alertCritical' :
             alert.severity === 'HIGH' ? 'alertHigh' : 'alertMedium',
      margin: [0, 2, 0, 2] as [number, number, number, number],
    }));

    content.push({
      stack: alertList,
      margin: [10, 0, 0, 10],
    } as Content);
  }

  return {
    stack: content,
    margin: [0, 0, 0, 20],
  };
}

/**
 * Create fleet summary content for PDF
 */
function createFleetSummaryContent(data: FleetStatusRow[]): Content {
  const totalTrains = data.reduce((sum, r) => sum + r.totalTrains, 0);
  const totalFit = data.reduce((sum, r) => sum + r.fitTrains, 0);
  const totalRestricted = data.reduce((sum, r) => sum + r.restrictedTrains, 0);
  const totalGrounded = data.reduce((sum, r) => sum + r.groundedTrains, 0);

  return {
    columns: [
      {
        width: '50%',
        stack: [
          { text: 'Fleet Overview', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Total Fleets:', style: 'summaryLabel' }, { text: String(data.length), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Trains:', style: 'summaryLabel' }, { text: String(totalTrains), style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
      {
        width: '50%',
        stack: [
          { text: 'Fitness Status', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'FIT:', style: 'summaryLabel' }, { text: `${totalFit} (${((totalFit / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
                [{ text: 'RESTRICTED:', style: 'summaryLabel' }, { text: `${totalRestricted} (${((totalRestricted / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
                [{ text: 'GROUNDED:', style: 'summaryLabel' }, { text: `${totalGrounded} (${((totalGrounded / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
    ],
    margin: [0, 0, 0, 20],
  };
}

// =============================================================================
// Utilities
// =============================================================================

/**
 * Ensure output directory exists
 */
async function ensureOutputDir(): Promise<void> {
  try {
    await fs.access(REPORTS_OUTPUT_DIR);
  } catch {
    await fs.mkdir(REPORTS_OUTPUT_DIR, { recursive: true });
    log.info({ dir: REPORTS_OUTPUT_DIR }, 'Created reports output directory');
  }
}

/**
 * Format file size for display
 */
function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Format report type as human-readable title
 */
function formatReportTitle(type: string): string {
  const titles: Record<string, string> = {
    pm_schedule: 'PM Schedule Export',
    fleet_status: 'Fleet Status Report',
    drift_report: 'Drift Analysis Report',
    tco_projection: 'TCO Projection Report',
  };
  return titles[type] ?? type;
}

/**
 * Register the report worker
 */
export function registerReportWorker(): void {
  log.info('Report worker processor available for registration');
}

