/**
 * Export Routes Tests
 *
 * Tests for the Export API endpoints.
 *
 * @see specs/005-api.md Section 5.15
 */

import { describe, it, expect, beforeEach, mock } from 'bun:test';
import { Hono } from 'hono';
import { exportRoutes } from './export';
import type { AppVariables } from '../types';

// Mock the queue module - import real module and override only what's needed
import * as realQueue from '../../lib/queue';
mock.module('../../lib/queue', () => ({
  ...realQueue,
  addJob: mock(() => Promise.resolve({ id: 'test-job-id' })),
  getJob: mock(() => Promise.resolve(null)),
}));

// Mock the logger - import real module and preserve other exports
import * as realLogger from '../../lib/logging/logger';
mock.module('../../lib/logging/logger', () => ({
  ...realLogger,
  logger: {
    info: mock(() => {}),
    debug: mock(() => {}),
    warn: mock(() => {}),
    error: mock(() => {}),
    child: mock(() => ({
      info: mock(() => {}),
      debug: mock(() => {}),
      warn: mock(() => {}),
      error: mock(() => {}),
    })),
  },
}));

// Mock the tracing module - import real module and override only what's needed
import * as realTracing from '../../lib/tracing';

// Create a mock span object that satisfies the OpenTelemetry Span interface
const mockSpan = {
  setAttribute: () => mockSpan,
  setAttributes: () => mockSpan,
  addEvent: () => mockSpan,
  setStatus: () => mockSpan,
  updateName: () => mockSpan,
  end: () => {},
  isRecording: () => false,
  recordException: () => {},
  spanContext: () => ({
    traceId: 'test-trace-id',
    spanId: 'test-span-id',
    traceFlags: 0,
  }),
};

mock.module('../../lib/tracing', () => ({
  ...realTracing,
  // Pass mock span to callback to prevent TypeError on span.setAttribute()
  withSpan: mock((_name: string, fn: (span: typeof mockSpan) => unknown) => fn(mockSpan)),
  withSpanSync: mock((_name: string, fn: (span: typeof mockSpan) => unknown) => fn(mockSpan)),
}));

// Mock the request-context middleware
mock.module('../middleware/request-context', () => ({
  getRequestId: mock(() => 'test-request-id'),
  getRequestDuration: mock(() => 42),
}));

describe('Export Routes', () => {
  let app: Hono<{ Variables: AppVariables }>;

  beforeEach(() => {
    app = new Hono<{ Variables: AppVariables }>();
    app.route('/', exportRoutes);
  });

  describe('POST /export/pm-schedule', () => {
    it('should queue a PM schedule export with xlsx format', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: 'xlsx',
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(body.data.jobId).toMatch(/^export-/);
      expect(body.data.status).toBe('QUEUED');
      expect(body.data.estimatedSizeBytes).toBeGreaterThan(0);
    });

    it('should queue a PM schedule export with csv format', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: 'csv',
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(body.data.status).toBe('QUEUED');
    });

    it('should queue export with filters', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: 'xlsx',
          filters: {
            depotId: 'depot-bishan',
            fromDate: '2026-01-01',
            toDate: '2026-12-31',
          },
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
    });

    it('should queue export with custom columns', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: 'xlsx',
          columns: ['trainNumber', 'pmCode', 'targetDate', 'status', 'assignedTrack'],
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
    });

    it('should return 400 for missing format', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });

      expect(res.status).toBe(400);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('VALIDATION_ERROR');
    });

    it('should return 400 for invalid format', async () => {
      const res = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: 'pdf',
        }),
      });

      expect(res.status).toBe(400);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('VALIDATION_ERROR');
    });
  });

  describe('POST /export/report', () => {
    it('should queue a weekly compliance report', async () => {
      const res = await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          reportType: 'WEEKLY_COMPLIANCE',
          parameters: {
            depotId: 'depot-bishan',
            weekOf: '2026-01-13',
          },
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(body.data.jobId).toMatch(/^report-/);
      expect(body.data.status).toBe('QUEUED');
    });

    it('should queue a fleet status report', async () => {
      const res = await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          reportType: 'FLEET_STATUS',
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
    });

    it('should queue a TCO projection report', async () => {
      const res = await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          reportType: 'TCO_PROJECTION',
          parameters: {
            fleetId: 'fleet-001',
          },
        }),
      });

      expect(res.status).toBe(202);

      const body = await res.json();
      expect(body.success).toBe(true);
    });

    it('should return 400 for missing reportType', async () => {
      const res = await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });

      expect(res.status).toBe(400);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('VALIDATION_ERROR');
    });

    it('should return 400 for invalid reportType', async () => {
      const res = await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          reportType: 'INVALID_REPORT',
        }),
      });

      expect(res.status).toBe(400);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('VALIDATION_ERROR');
    });
  });

  describe('GET /export/:jobId', () => {
    it('should return job status for existing job', async () => {
      // First create a job
      const createRes = await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ format: 'xlsx' }),
      });
      const createBody = await createRes.json();
      const jobId = createBody.data.jobId;

      // Get its status
      const res = await app.request(`/export/${jobId}`);

      expect(res.status).toBe(200);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(body.data.jobId).toBe(jobId);
      expect(body.data.status).toBe('QUEUED');
    });

    it('should return 404 for non-existent job', async () => {
      const res = await app.request('/export/non-existent-job');

      expect(res.status).toBe(404);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('NOT_FOUND');
    });
  });

  describe('GET /export/jobs', () => {
    it('should list export jobs', async () => {
      // Create a job first
      await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ format: 'xlsx' }),
      });

      const res = await app.request('/export/jobs');

      expect(res.status).toBe(200);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(Array.isArray(body.data)).toBe(true);
      expect(body.meta?.pagination).toBeDefined();
    });

    it('should support pagination', async () => {
      const res = await app.request('/export/jobs?page=1&pageSize=5');

      expect(res.status).toBe(200);

      const body = await res.json();
      expect(body.meta?.pagination.page).toBe(1);
      expect(body.meta?.pagination.pageSize).toBe(5);
    });

    it('should filter by status', async () => {
      const res = await app.request('/export/jobs?status=QUEUED');

      expect(res.status).toBe(200);

      const body = await res.json();
      expect(body.success).toBe(true);
      // All returned jobs should have QUEUED status
      body.data.forEach((job: { status: string }) => {
        expect(job.status).toBe('QUEUED');
      });
    });

    it('should filter by type', async () => {
      // Create both types of jobs
      await app.request('/export/pm-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ format: 'xlsx' }),
      });

      await app.request('/export/report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ reportType: 'FLEET_STATUS' }),
      });

      const pmRes = await app.request('/export/jobs?type=pm_schedule');
      const reportRes = await app.request('/export/jobs?type=report');

      expect(pmRes.status).toBe(200);
      expect(reportRes.status).toBe(200);

      const pmBody = await pmRes.json();
      const reportBody = await reportRes.json();

      pmBody.data.forEach((job: { type: string }) => {
        expect(job.type).toBe('pm_schedule');
      });

      reportBody.data.forEach((job: { type: string }) => {
        expect(job.type).toBe('report');
      });
    });
  });

  describe('POST /export/cleanup', () => {
    it('should trigger cleanup and return count', async () => {
      const res = await app.request('/export/cleanup', {
        method: 'POST',
      });

      expect(res.status).toBe(200);

      const body = await res.json();
      expect(body.success).toBe(true);
      expect(body.data.message).toBe('Cleanup completed');
      expect(typeof body.data.cleanedCount).toBe('number');
    });
  });
});

/**
 * MMS API Server Entry Point
 *
 * Starts the Hono server using Bun runtime with dynamic port allocation.
 * Use this file to start the API server standalone.
 *
 * Usage: bun run src/api/server.ts
 *
 * Environment Variables:
 * - PORT: Server port (default: 0 = random available port)
 * - HOST: Server host (default: 0.0.0.0)
 * - NODE_ENV: Environment (development, production, test)
 *
 * Dynamic Port Support:
 * - PORT=0 assigns a random available port (recommended for dev/testing)
 * - The actual assigned port is logged and written to stdout for parsing
 * - Look for "API_SERVER_PORT=<port>" in output to get the actual port
 */

import { getApp } from './index';
import { logger } from '../lib/logging/logger';

const PORT = process.env.PORT !== undefined ? Number(process.env.PORT) : 0;
const HOST = process.env.HOST || '0.0.0.0';

const app = getApp();

const server = Bun.serve({
  port: PORT,
  hostname: HOST,
  fetch: app.fetch,
});

// Output actual assigned port (useful for scripts and test harnesses)
const actualPort = server.port;
console.log(`API_SERVER_PORT=${actualPort}`);

logger.info(
  { port: actualPort, host: HOST, env: process.env.NODE_ENV },
  `MMS API server listening on http://${HOST}:${actualPort}`
);

export { server, actualPort };

