/**
 * MMS REST API
 *
 * Main Hono application setup with middleware and route registration.
 * Provides RESTful endpoints for the Metro Fleet Mileage Management System.
 *
 * Base URL: /api/v1
 * Authentication: Bearer JWT
 * Rate Limiting: 100 requests/minute per user (Redis sliding window)
 *
 * @see specs/005-api.md
 */

import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { logger as honoLogger } from 'hono/logger';
import { secureHeaders } from 'hono/secure-headers';
import { timing } from 'hono/timing';
import {
  requestContext,
  createErrorHandler,
  notFoundHandler,
  tracingMiddleware,
  rateLimiter,
  strictRateLimiter,
} from './middleware';
import { authRoutes, fleetRoutes, pmScheduleRoutes, mileageRoutes, optimizerRoutes, baselineRoutes, driftRoutes, manhourRoutes, canvasRoutes, costingRoutes, materialRoutes, scenarioRoutes, exportRoutes, integrationRoutes, baselineAssumptionRoutes, unavailabilityRoutes, serviceDemandRoutes, routeUtilizationRoutes, trackCapabilitiesRoutes, trainRouteCompatibilityRoutes } from './routes';
import { success, type AppVariables } from './types';
import { logger } from '../lib/logging/logger';
import { createOpenApiRoutes } from './openapi';
import { getMetrics, getMetricsContentType } from '../lib/metrics';
import { checkDatabaseHealth } from '../lib/db/connection';
import { checkRedisHealth } from '../lib/redis/connection';

/**
 * Create the main Hono application
 */
export function createApp(): Hono<{ Variables: AppVariables }> {
  const app = new Hono<{ Variables: AppVariables }>();

  // ==========================================================================
  // Global Middleware
  // ==========================================================================

  // Security headers
  app.use('*', secureHeaders());

  // CORS configuration
  app.use(
    '*',
    cors({
      origin: (origin) => {
        // Allow localhost for development
        if (!origin) return '';
        if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
          return origin;
        }
        // Add production origins here
        return '';
      },
      allowMethods: ['GET', 'POST', 'PATCH', 'PUT', 'DELETE', 'OPTIONS'],
      allowHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
      exposeHeaders: ['X-Request-ID', 'X-Response-Time'],
      maxAge: 3600,
      credentials: true,
    })
  );

  // Request ID and timing
  app.use('*', requestContext());

  // Server timing headers
  app.use('*', timing());

  // Request logging (development)
  if (process.env.NODE_ENV !== 'production') {
    app.use('*', honoLogger());
  }

  // OpenTelemetry tracing
  app.use('*', tracingMiddleware());

  // Rate limiting (100 requests/minute per user, spec 005)
  // Applied after auth middleware so we can use user ID for rate limiting
  app.use('/api/*', rateLimiter({
    // Skip rate limiting for health endpoints and docs
    skip: (c) => {
      const path = c.req.path;
      return path === '/api/v1' || path === '/api/v1/docs';
    },
  }));

  // Stricter rate limiting for auth endpoints (10 requests/minute)
  app.use('/api/v1/auth/*', strictRateLimiter());

  // ==========================================================================
  // Health Endpoints (outside /api/v1)
  // ==========================================================================

  /**
   * GET /health
   *
   * Liveness probe - returns 200 if process is running.
   */
  app.get('/health', (c) => {
    return c.json({ status: 'healthy', timestamp: new Date().toISOString() });
  });

  /**
   * GET /ready
   *
   * Readiness probe - returns 200 if service is ready to accept traffic.
   * Checks database and Redis connections with timeout.
   *
   * @returns 200 if all services healthy, 503 if any service unhealthy
   */
  app.get('/ready', async (c) => {
    const HEALTH_CHECK_TIMEOUT = 5000; // 5 seconds

    // Helper to add timeout to health check
    const withTimeout = async (
      promise: Promise<boolean>,
      timeoutMs: number,
      name: string
    ): Promise<{ healthy: boolean; error?: string }> => {
      try {
        const result = await Promise.race([
          promise.then((ok) => ({ ok, timeout: false as const })),
          new Promise<{ ok: boolean; timeout: true }>((resolve) =>
            setTimeout(() => resolve({ ok: false, timeout: true }), timeoutMs)
          ),
        ]);
        if (result.timeout) {
          return { healthy: false, error: `${name} health check timeout` };
        }
        return { healthy: result.ok };
      } catch (err) {
        return { healthy: false, error: err instanceof Error ? err.message : 'Unknown error' };
      }
    };

    // Run health checks in parallel with timeout
    const [dbHealth, redisHealth] = await Promise.all([
      withTimeout(checkDatabaseHealth(), HEALTH_CHECK_TIMEOUT, 'Database'),
      withTimeout(checkRedisHealth(), HEALTH_CHECK_TIMEOUT, 'Redis'),
    ]);

    const checks = {
      database: dbHealth.healthy ? 'healthy' : 'unhealthy',
      databaseError: dbHealth.error,
